// UBICACION: public/js/auth-guard.js
(function() {
    const userStr = sessionStorage.getItem('user');
    const path = window.location.pathname;

    if (!userStr && !path.includes('login.html') && !path.includes('registro.html')) {
        window.location.replace('login.html');
        return;
    }
    if (userStr && (path.includes('login.html') || path.includes('registro.html'))) {
        window.location.replace('index.html');
        return;
    }

    function inyectarPerfil() {
        if (!userStr) return;
        const user = JSON.parse(userStr);
        const nav = document.querySelector('.topbar');

        if (nav && !document.getElementById('user-badge-global')) {
            let partes = user.nombre_completo.split(' ');
            let iniciales = partes[0][0] + (partes[1] ? partes[1][0] : '');

            const badge = document.createElement('ul');
            badge.className = 'navbar-nav ml-auto';
            badge.id = 'user-badge-global';
            badge.innerHTML = `


                    ${partes[0]}


                        ${iniciales.toUpperCase()}

                `;
            nav.appendChild(badge);

            // SEGURIDAD DE ROLES: Ocultar botones si id_rol !== 1 (Admin)
            if (user.id_rol !== 1) {
                const style = document.createElement('style');
                style.innerHTML = `
                    .btn-outline-danger, .btn-outline-warning, .btn-eliminar, .btn-editar,
                    [onclick*="eliminar"], [onclick*="abrirModalEditar"], #btn-agregar-arbol { 
                        display: none !important; 
                    }
                `;
                document.head.appendChild(style);
            }
        }
    }

    if (document.readyState === 'loading') { document.addEventListener('DOMContentLoaded', inyectarPerfil); }
    else { inyectarPerfil(); }
    setTimeout(inyectarPerfil, 500);
})();

window.cerrarSesion = (e) => { 
    if(e) e.preventDefault(); 
    sessionStorage.clear(); 
    window.location.replace('login.html'); 
};



let miniMapa;

document.addEventListener('DOMContentLoaded', async () => {
    const sidebarContainer = document.getElementById('sidebar-container');
    const mostrarPagina = () => document.body.classList.add('listo');

    try {
        const cachedSidebar = sessionStorage.getItem('sidebarHTML');
        if (cachedSidebar) {
            sidebarContainer.innerHTML = cachedSidebar;
        } else {
            const res = await fetch('components/sidebar.html');
            if (res.ok) {
                const html = await res.text();
                sessionStorage.setItem('sidebarHTML', html);
                sidebarContainer.innerHTML = html;
            }
        }
    } catch (err) {
        console.error("Error cargando sidebar:", err);
    } finally {
        setTimeout(mostrarPagina, 100);
    }

    const etiqueta = new URLSearchParams(window.location.search).get('id');
    if (!etiqueta) return window.location.href = "inventario.html";

    const inputIDArbolModal = document.getElementById('inputIDArbolModal');
    if (inputIDArbolModal) inputIDArbolModal.value = etiqueta;

    cargarExpediente(etiqueta);

    const formSeguimiento = document.getElementById('formSeguimiento');
    if (formSeguimiento) {
        formSeguimiento.addEventListener('submit', async function (e) {
            e.preventDefault();

            const btn = this.querySelector('button[type="submit"]');
            const txt = btn.innerHTML;
            btn.innerHTML = 'Guardando...';
            btn.disabled = true;

            try {
                const formData = new FormData(this);
                const sessionData = JSON.parse(sessionStorage.getItem('user'));
                if (sessionData) formData.append('id_usuario', sessionData.id_usuario);

                const res = await fetch('/api/seguimiento', {
                    method: 'POST',
                    body: formData
                });

                const data = await res.json();
                if (data.success) {
                    $('#modalSeguimiento').modal('hide');
                    this.reset();
                    cargarExpediente(etiqueta);
                }
            } catch (err) {
                console.error(err);
            } finally {
                btn.innerHTML = txt;
                btn.disabled = false;
            }
        });
    }

    const formEditarReporte = document.getElementById('formEditarReporte');
    if (formEditarReporte) {
        formEditarReporte.addEventListener('submit', async function (e) {
            e.preventDefault();

            const btn = this.querySelector('button[type="submit"]');
            const txt = btn.innerHTML;
            btn.innerHTML = 'Actualizando...';
            btn.disabled = true;

            const id = document.getElementById('edit-rep-id').value;

            const data = {
                estado_salud: document.getElementById('edit-rep-estado').value,
                comentarios: document.getElementById('edit-rep-comentarios').value
            };

            try {
                const res = await fetch(`/api/seguimiento/${id}`, {
                    method: 'PUT',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(data)
                });

                const result = await res.json();
                if (result.success) {
                    $('#modalEditarReporte').modal('hide');
                    cargarExpediente(etiqueta);
                }
            } catch (err) {
                console.error(err);
            } finally {
                btn.innerHTML = txt;
                btn.disabled = false;
            }
        });
    }
});

async function cargarExpediente(codigo) {
    try {
        const res = await fetch(`/api/arbol/expediente/${codigo}`);
        if (!res.ok) throw new Error("Arbol no encontrado");

        const data = await res.json();

        const a = data.arbol;
        const reportes = data.historial; // corregido

        document.getElementById('det-nombre-comun').innerText = a.nombre_comun;
        document.getElementById('det-nombre-cientifico').innerText = a.nombre_cientifico || 'Sin registro';
        document.getElementById('det-descripcion').innerText = a.descripcion || 'Sin descripcion';
        document.getElementById('det-codigo').innerText = a.codigo_etiqueta;
        document.getElementById('det-zona').innerHTML = `${a.nombre_zona || 'Sin zona'}`;

        let fPlantado = new Date(a.fecha_plantado);
        fPlantado.setMinutes(fPlantado.getMinutes() + fPlantado.getTimezoneOffset());
        document.getElementById('det-fecha').innerText = fPlantado.toLocaleDateString();

        document.getElementById('det-coords').innerText = `Lat: ${a.latitud} | Lng: ${a.longitud}`;

        if (!miniMapa) {
            miniMapa = L.map('mini-mapa', { zoomControl: false })
                .setView([a.latitud, a.longitud], 18);

            L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png')
                .addTo(miniMapa);
        } else {
            miniMapa.setView([a.latitud, a.longitud], 18);
        }

        miniMapa.eachLayer(layer => {
            if (layer instanceof L.Marker) miniMapa.removeLayer(layer);
        });

        L.marker([a.latitud, a.longitud]).addTo(miniMapa);

        const contenedor = document.getElementById('contenedor-historial');

        if (contenedor) {
            contenedor.innerHTML = '';

            if (!reportes || reportes.length === 0) {
                contenedor.innerHTML = '
Sin registros';
                return;
            }

            reportes.forEach((r) => {
                const badge = r.estado_salud === 'Bueno' ? 'success' :
                    (r.estado_salud === 'Regular' ? 'warning' : 'danger');

                const foto = r.foto_url ? `/uploads/${r.foto_url}` : '';

                let fRevision = new Date(r.fecha_revision);
                fRevision.setMinutes(fRevision.getMinutes() + fRevision.getTimezoneOffset());

                contenedor.innerHTML += `




                            ${fRevision.toLocaleDateString()}
                            ${r.estado_salud}


${r.comentarios || ''}
                        ${foto ? `` : ''}

                `;
            });
        }

    } catch (e) {
        console.error("Error al cargar expediente:", e);
    }
}



// UBICACIÓN: public/js/detalles_reforestacion-logic.js

document.addEventListener('DOMContentLoaded', async () => {
    // 1. CARGA DE SIDEBAR (Seguro Anti-Pantallazos)
    const sidebarContainer = document.getElementById('sidebar-container');
    const mostrarPagina = () => document.body.classList.add('listo');

    try {
        const cachedSidebar = sessionStorage.getItem('sidebarHTML');
        if (cachedSidebar) {
            sidebarContainer.innerHTML = cachedSidebar;
        } else {
            const res = await fetch('components/sidebar.html');
            if(res.ok) {
                const html = await res.text();
                sessionStorage.setItem('sidebarHTML', html);
                sidebarContainer.innerHTML = html;
            }
        }
    } catch (err) {
        console.error("Error sidebar:", err);
    } finally {
        setTimeout(mostrarPagina, 100); // Fuerza a mostrar la página siempre
    }

    // 2. Obtener ID de la URL
    const idCampana = new URLSearchParams(window.location.search).get('id');
    if (!idCampana) return window.location.href = "reforestacion.html";

    cargarDetallesCampana(idCampana);
});

async function cargarDetallesCampana(id) {
    try {
        const res = await fetch(`/api/reforestacion/detalles/${id}`);

        // Si el servidor Node.js marca error (ej. campaña no existe)
        if (!res.ok) {
            const errorData = await res.json();
            throw new Error(errorData.error || 'Error interno del servidor.');
        }

        const data = await res.json();
        const c = data.campana;
        const arboles = data.arboles;

        // ==========================================
        // FUNCIÓN PROTECTORA DE INYECCIÓN
        // ==========================================
        // Evita que el JS choque si algún ID del HTML no se encuentra
        const setEl = (idElemento, contenido) => {
            const el = document.getElementById(idElemento);
            if(el) el.innerHTML = contenido;
        };

        // 1. Inyectar Textos Generales
        setEl('det-nombre-campana', c.nombre_propuesta);
        setEl('det-zona', c.nombre_zona || 'Sin zona asignada');

        let fechaTxt = '- Sin fecha -';
        if(c.fecha_evento) {
            let f = new Date(c.fecha_evento);
            f.setMinutes(f.getMinutes() + f.getTimezoneOffset());
            fechaTxt = `${f.getDate().toString().padStart(2,'0')}/${(f.getMonth()+1).toString().padStart(2,'0')}/${f.getFullYear()}`;
        }
        setEl('det-fecha', fechaTxt);

        let badgeClass = c.estado === 'Completada' ? 'success' : (c.estado === 'En curso' ? 'info' : 'warning');
        setEl('det-estado', `${c.estado}`);

        // 2. Inyectar Barra de Progreso
        let plantados = c.cantidad_plantada || 0;
        let meta = c.cantidad_esperada || 1;
        let pct = Math.round((plantados / meta) * 100); // Porcentaje real

        setEl('det-progreso-texto', `${plantados} / ${meta} Árboles`);
        setEl('det-progreso-pct', `${pct}% Completado`);
        setEl('badge-total-arboles', `${arboles.length} Árbol(es)`);

        const barra = document.getElementById('det-progreso-barra');
        if(barra) barra.style.width = `${Math.min(pct, 100)}%`; // Evita que la barra se desborde visualmente si pasa del 100%

        // 3. Inyectar Tabla de Árboles
        const tbody = document.getElementById('tbody-arboles-campana');
        if(!tbody) return; 

        tbody.innerHTML = '';

        if (arboles.length === 0) {
            tbody.innerHTML = '
Aún no se han registrado ejemplares bajo esta campaña.';
            return;
        }

        arboles.forEach(a => {
            let estado = a.estado_actual || 'Bueno';
            let estBadge = estado === 'Bueno' ? 'success' : (estado === 'Regular' ? 'warning' : 'danger');

            let fRegistro = '-';
            if(a.fecha_plantado) {
                let f2 = new Date(a.fecha_plantado);
                f2.setMinutes(f2.getMinutes() + f2.getTimezoneOffset());
                fRegistro = `${f2.getDate().toString().padStart(2,'0')}/${(f2.getMonth()+1).toString().padStart(2,'0')}/${f2.getFullYear()}`;
            }

            tbody.innerHTML += `


                    ${a.id_arbol}
                    ${a.codigo_etiqueta}


${a.nombre_comun}

${a.nombre_cientifico || 'Sin registro científico'}

                    ${fRegistro}
                    ${estado}




            `;
        });

    } catch (error) {
        // SI ALGO FALLA, LO MOSTRAMOS EN PANTALLA EN LUGAR DE CONGELARSE
        console.error("Error crítico capturado:", error);

        const titulo = document.getElementById('det-nombre-campana');
        if(titulo) titulo.innerText = 'Error de Carga';

        const tbody = document.getElementById('tbody-arboles-campana');
        if(tbody) {
            tbody.innerHTML = `





Error en la conexión o base de datos.
                        ${error.message}

                `;
        }
    }
}



// UBICACION: public/js/perfil-logic.js

document.addEventListener('DOMContentLoaded', async () => {
    const sidebarContainer = document.getElementById('sidebar-container');
    const mostrarPagina = () => document.body.classList.add('listo');

    try {
        const cachedSidebar = sessionStorage.getItem('sidebarHTML');
        if (cachedSidebar) {
            sidebarContainer.innerHTML = cachedSidebar;
        } else {
            const res = await fetch('components/sidebar.html');
            if (res.ok) {
                const html = await res.text();
                sessionStorage.setItem('sidebarHTML', html); 
                sidebarContainer.innerHTML = html;
            }
        }
    } catch (err) { console.error(err); }
    finally { setTimeout(mostrarPagina, 100); }

    const sessionData = sessionStorage.getItem('user');
    if (!sessionData) { window.location.href = 'login.html'; return; }

    const usuarioActual = JSON.parse(sessionData);
    cargarDatosPerfil(usuarioActual);
});

async function cargarDatosPerfil(user) {
    try {
        const res = await fetch(`/api/perfil/${user.id_usuario}`);
        const data = await res.json();
        if (data.error) return alert("Error al cargar el perfil");

        const info = data.usuario;
        const arboles = data.arboles;

        let partesNombre = info.nombre_completo.trim().split(' ');
        let iniciales = partesNombre[0].charAt(0).toUpperCase();
        if (partesNombre.length > 1) iniciales += partesNombre[1].charAt(0).toUpperCase();

        document.getElementById('topbar-name').innerText = partesNombre[0];
        document.getElementById('topbar-initials').innerText = iniciales;
        document.getElementById('perfil-iniciales').innerText = iniciales;
        document.getElementById('perfil-nombre').innerText = info.nombre_completo;
        document.getElementById('perfil-matricula').innerText = info.matricula;
        document.getElementById('perfil-rol').innerText = info.rol;
        document.getElementById('perfil-conteo').innerText = arboles.length;

        const contenedor = document.getElementById('contenedor-arboles');
        contenedor.innerHTML = '';

        if (arboles.length === 0) {
            contenedor.innerHTML = `





Aun no has apadrinado ningun arbol
                    Ir al Inventario
                `;
            return;
        }

        arboles.forEach(a => {
            let badgeClass = a.estado_actual === 'Bueno' ? 'success' : (a.estado_actual === 'Regular' ? 'warning text-dark' : 'danger');
            let foto = a.foto ? `/uploads/${a.foto}` : 'https://cdn-icons-png.flaticon.com/512/10521/10521236.png';
            let fAdopcion = new Date(a.fecha_asignacion);
            fAdopcion.setMinutes(fAdopcion.getMinutes() + fAdopcion.getTimezoneOffset());

            contenedor.innerHTML += `







                            ${a.estado_actual || 'Desconocido'}




${a.nombre_comun}

${a.nombre_cientifico || 'Sin clasificar'}

${a.nombre_zona || 'Campus General'}

${a.codigo_etiqueta}

                                 Cuidar / Reportar




                            Adoptado el: ${fAdopcion.toLocaleDateString()}


                `;
        });
    } catch (e) { console.error("Error cargando perfil:", e); }
}



