let chartPie;

document.addEventListener('DOMContentLoaded', async () => {
    // 1. ESTO ERA LO QUE FALTABA: Cargar el menú y mostrar la página
    const sidebarContainer = document.getElementById('sidebar-container');
    const mostrarPagina = () => document.body.classList.add('listo');

    try {
        const res = await fetch('components/sidebar.html');
        const html = await res.text();
        sidebarContainer.innerHTML = html;
    } catch (err) { 
        console.error("Error sidebar:", err); 
    } finally { 
        setTimeout(mostrarPagina, 100); 
    }

    // 2. Cargar las estadísticas de los árboles
    cargarStats();
});

async function cargarStats() {
    try {
        const res = await fetch('/api/dashboard-stats');
        const data = await res.json();

        document.getElementById('total-arboles').innerText = data.totalArboles;
        document.getElementById('total-especies').innerText = data.totalEspecies;
        document.getElementById('total-sanos').innerText = data.totalSanos;

        const b = data.totalSanos;
        const r = Math.floor((data.totalArboles - b) / 2); 
        const m = data.totalArboles - b - r;
        generarGrafica(b, r, m);
    } catch (e) { console.error("Error cargando stats:", e); }
}

// 3. LA MAGIA DEL TICKET (Ya con datos reales del servidor)
window.generarTicketPDF = async function() {
    const ticketElement = document.getElementById('ticketPDF');
    if (!ticketElement) return alert("Error: No se encontro el diseno del ticket en el HTML.");

    try {
        const res = await fetch('/api/dashboard-stats');
        const data = await res.json();

        // Rellenamos el HTML oculto con los datos
        document.getElementById('ticket-folio').innerText = 'UTM-' + Date.now().toString().slice(-4);
        document.getElementById('ticket-fecha').innerText = new Date().toLocaleDateString();
        document.getElementById('ticket-total').innerText = data.totalArboles;
        document.getElementById('ticket-sanos').innerText = data.totalSanos;
        document.getElementById('ticket-riesgo').innerText = data.totalArboles - data.totalSanos;

        const salud = data.totalArboles > 0 ? Math.round((data.totalSanos / data.totalArboles) * 100) : 0;
        document.getElementById('ticket-porcentaje').innerText = salud + '%';

        // Mostramos para la foto
        ticketElement.style.display = 'block'; 

        const opt = {
            margin:       10,
            filename:     'Ticket_ArboMap_Real.pdf',
            image:        { type: 'jpeg', quality: 0.98 },
            html2canvas:  { scale: 2 },
            jsPDF:        { unit: 'mm', format: 'a5', orientation: 'portrait' }
        };

        html2pdf().set(opt).from(ticketElement).save().then(() => {
            // Ocultamos después de la foto
            ticketElement.style.display = 'none'; 
        });

    } catch (err) {
        console.error("Error al generar ticket con datos reales:", err);
        alert("Error al generar los datos del ticket.");
    }
}

// 4. GRÁFICA DE DONA
function generarGrafica(b, r, m) {
    if(chartPie) chartPie.destroy();
    const canvas = document.getElementById("myPieChart");
    if(canvas) {
        chartPie = new Chart(canvas, {
            type: 'doughnut',
            data: { 
                labels: ["Bueno", "Regular", "Malo"], 
                datasets: [{ data: [b, r, m], backgroundColor: ['#1cc88a', '#f6c23e', '#e74a3b'] }] 
            },
            options: { maintainAspectRatio: false, legend: { display: false }, cutoutPercentage: 80 }
        });
    }
}



// UBICACIÓN: public/js/index-logic.js

document.addEventListener('DOMContentLoaded', async () => {

    // 1. Cargar el Menú Lateral y mostrar la página suavemente para evitar parpadeos
    fetch('components/sidebar.html')
        .then(response => response.text())
        .then(html => {
            document.getElementById('sidebar-container').innerHTML = html;

            // Forzamos un micro-retraso (50ms) para que el navegador acomode el menú ANTES de prender la luz (Anti-Ghosting Bulletproof)
            setTimeout(() => {
                document.body.classList.add('listo');
            }, 50);
        })
        .catch(error => console.error("Error al cargar el menú:", error));

    try {
        // 2. Traer estadísticas de la BD (Node.js API)
        const responseStats = await fetch('/api/dashboard-stats');
        const dataStats = await responseStats.json();

        // 3. Llenar Tarjetas Superiores
        document.getElementById('tot-arboles').textContent = dataStats.totalArboles || 0;
        document.getElementById('tot-especies').textContent = dataStats.totalEspecies || 0;
        document.getElementById('tot-sanos').textContent = dataStats.totalSanos || 0;

        // 4. Preparar datos para la Gráfica de Dona
        let buenos = 0; 
        let regulares = 0; 
        let malos = 0; 
        let sinRevisar = 0;

        if(dataStats.arboles) {
            dataStats.arboles.forEach(arbol => {
                if(arbol.estado === 'Bueno') buenos++;
                else if(arbol.estado === 'Regular') regulares++;
                else if(arbol.estado === 'Malo') malos++;
                else sinRevisar++; 
            });
        }

        // 5. Configurar e instanciar Gráfica de Dona (con Animación)
        const ctxElement = document.getElementById('saludPieChart');
        if (ctxElement) {
            const ctx = ctxElement.getContext('2d');
            new Chart(ctx, {
                type: 'doughnut',
                data: {
                    labels: ['Bueno', 'Regular', 'Malo', 'Sin Revisión'],
                    datasets: [{
                        data: [buenos, regulares, malos, sinRevisar],
                        backgroundColor: ['#1cc88a', '#f6c23e', '#e74a3b', '#858796'], 
                        hoverBackgroundColor: ['#17a673', '#dda20a', '#be2617', '#6e707e'],
                        hoverBorderColor: "rgba(234, 236, 244, 1)",
                        borderWidth: 1,
                        borderColor: '#1a2e1f' // Borde oscuro para que combine con el fondo
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    cutout: '70%', 
                    animation: {
                        animateRotate: true,
                        animateScale: true,
                        duration: 1500, 
                        easing: 'easeOutQuart'
                    },
                    plugins: {
                        legend: { 
                            position: 'bottom', 
                            labels: { color: '#fff', padding: 20 } 
                        }
                    }
                }
            });
        }

        // 6. Configurar Mapa ITM 
        const mapElement = document.getElementById('dashboardMap');
        if (mapElement) {
            const map = L.map('dashboardMap').setView([19.7267, -101.1619], 16);

            L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
                attribution: '© OSM'
            }).addTo(map);

            // 7. Dibujar Zonas (Polígonos verdes transparentes)
            const responseSitios = await fetch('/api/sitios');
            const sitios = await responseSitios.json();

            sitios.forEach(sitio => {
                if (sitio.coordenadas_poligono) {
                    try {
                        const geojsonData = JSON.parse(sitio.coordenadas_poligono);
                        L.geoJSON(geojsonData, {
                            style: { color: '#1e7e34', weight: 2, fillColor: '#28a745', fillOpacity: 0.3 }
                        }).bindPopup(`${sitio.nombre_zona}`).addTo(map);
                    } catch(e) { 
                        console.error("Error en polígono", e); 
                    }
                }
            });

            // 8. Dibujar Puntos de Árboles (Con tu ícono personalizado)
            const treeIcon = L.icon({
                iconUrl: 'https://cdn-icons-png.flaticon.com/512/10521/10521236.png', 
                iconSize: [25, 25], 
                iconAnchor: [12, 25], 
                popupAnchor: [0, -25]
            });

            if(dataStats.arboles) {
                dataStats.arboles.forEach(arbol => {
                    const lat = parseFloat(arbol.latitud);
                    const lng = parseFloat(arbol.longitud);

                    if (!isNaN(lat) && !isNaN(lng)) {
                        let color = arbol.estado === 'Malo' ? 'red' : (arbol.estado === 'Regular' ? 'orange' : 'green');
                        let popupHtml = `
${arbol.nombre_comun}
${arbol.estado || 'Sin Revisión'}`;

                        L.marker([lat, lng], {icon: treeIcon})
                         .addTo(map)
                         .bindPopup(popupHtml);
                    }
                });
            }
        }

    } catch (error) {
        console.error("Error cargando el Dashboard:", error);
    }
});



// UBICACION: public/js/inventario-logic.js
let todosLosArboles = [];
let mapRegistro;
let markerRegistro;
let poligonosZonas = [];

document.addEventListener('DOMContentLoaded', () => {
    // 1. Cargar el Menu Lateral
    const sidebarContainer = document.getElementById('sidebar-container');
    const cachedSidebar = sessionStorage.getItem('sidebarHTML');
    if (cachedSidebar) {
        sidebarContainer.innerHTML = cachedSidebar;
        document.body.classList.add('listo');
    } else {
        fetch('components/sidebar.html').then(r => r.text()).then(html => {
            sessionStorage.setItem('sidebarHTML', html); 
            sidebarContainer.innerHTML = html;
            setTimeout(() => { document.body.classList.add('listo'); }, 10);
        });
    }

    // 2. Inicializar la tabla, filtros y campanas
    cargarTablaInventario();
    cargarCampanasSelect();

    document.getElementById('filtro-texto').addEventListener('input', aplicarFiltros);
    document.getElementById('filtro-zona').addEventListener('change', aplicarFiltros);
    document.getElementById('filtro-estado').addEventListener('change', aplicarFiltros);

    // 3. Listener: Crear Nuevo Arbol
    document.getElementById('formAgregarArbol').addEventListener('submit', async function(e) {
        e.preventDefault(); 
        const btn = this.querySelector('button[type="submit"]');
        const textoOriginal = btn.innerHTML;
        btn.innerHTML = 'Guardando...'; btn.disabled = true;

        try {
            const formData = new FormData(this);

            // Agregar el ID del usuario logueado a la peticion
            const sessionData = JSON.parse(sessionStorage.getItem('user'));
            if(sessionData) formData.append('id_usuario', sessionData.id_usuario);

            const res = await fetch('/api/arboles', { method: 'POST', body: formData });
            const data = await res.json();

            if(data.success) {
                $('#modalNuevoArbol').modal('hide');
                this.reset();
                if(markerRegistro) mapRegistro.removeLayer(markerRegistro);
                document.getElementById('zona-detectada-text').innerText = 'Esperando ubicacion...';
                cargarTablaInventario();
            } else {
                alert("Error al guardar: " + data.message);
            }
        } catch (err) { 
            console.error(err); 
        } finally { 
            btn.innerHTML = textoOriginal; btn.disabled = false; 
        }
    });

    // 4. Listener: Actualizar Arbol Existente (CRUD: Update)
    document.getElementById('formEditarArbol').addEventListener('submit', async function(e) {
        e.preventDefault();
        const btn = this.querySelector('button[type="submit"]');
        const textoOriginal = btn.innerHTML;
        btn.innerHTML = 'Actualizando...'; btn.disabled = true;

        const id = document.getElementById('edit-id_arbol').value;
        const data = Object.fromEntries(new FormData(this).entries());

        try {
            const res = await fetch(`/api/arboles/${id}`, {
                method: 'PUT', 
                headers: {'Content-Type': 'application/json'}, 
                body: JSON.stringify(data)
            });
            if((await res.json()).success) {
                $('#modalEditarArbol').modal('hide');
                cargarTablaInventario();
            }
        } catch(err) { 
            console.error(err); 
        } finally {
            btn.innerHTML = textoOriginal; btn.disabled = false;
        }
    });
});

// Funcion: Dibujar la tabla con los datos actuales
function renderizarTabla(arboles) {
    const tbody = document.getElementById('tbody-arboles');
    tbody.innerHTML = ''; 
    arboles.forEach((a, i) => {
        let badge = a.estado === 'Bueno' ? 'success' : (a.estado === 'Regular' ? 'warning' : 'danger');
        let foto = a.foto_actual ? `/uploads/${a.foto_actual}` : 'https://cdn-icons-png.flaticon.com/512/10521/10521236.png';
        let zonaNombre = a.nombre_zona ? a.nombre_zona : 'Sin zona asignada';

        tbody.innerHTML += `


                ${a.id_arbol || (i+1)}



${a.nombre_comun}

${a.nombre_cientifico || 'Sin registro'}
                    ${a.codigo_etiqueta}


${zonaNombre}${a.latitud}, ${a.longitud}
                ${a.estado || 'N/A'}





            `;
    });
}

// Funcion: Buscador y filtros desplegables
function aplicarFiltros() {
    const txt = document.getElementById('filtro-texto').value.toLowerCase();
    const z = document.getElementById('filtro-zona').value;
    const e = document.getElementById('filtro-estado').value;
    renderizarTabla(todosLosArboles.filter(a => 
        (a.nombre_comun.toLowerCase().includes(txt) || a.codigo_etiqueta.toLowerCase().includes(txt)) &&
        (z === 'Todas' || (a.nombre_zona || 'General') === z) && (e === 'Todos' || a.estado === e)
    ));
}

// Funcion: Obtener datos de la BD
function cargarTablaInventario() {
    fetch('/api/dashboard-stats').then(res => res.json()).then(data => {
        todosLosArboles = data.arboles;
        const sel = document.getElementById('filtro-zona');
        sel.innerHTML = 'Todas las Zonas';
        [...new Set(data.arboles.map(x => x.nombre_zona).filter(z => z))].forEach(z => sel.innerHTML += `${z}`);
        renderizarTabla(todosLosArboles);
    });
}

// Funcion: Cargar campañas para el modal de nuevo arbol
async function cargarCampanasSelect() {
    try {
        const res = await fetch('/api/campanas-activas');
        const campanas = await res.json();
        const sel = document.querySelector('select[name="id_reforestacion"]');
        if(sel) {
            sel.innerHTML = 'No (Arbol ya existente)';
            campanas.forEach(c => {
                sel.innerHTML += `${c.nombre_propuesta}`;
            });
        }
    } catch (e) { console.error("Error al cargar campanas", e); }
}

// ==========================================
// FUNCIONES DE EDICION Y BORRADO
// ==========================================
window.abrirModalEditar = async function(id) {
    try {
        const res = await fetch(`/api/arboles/${id}`);
        if (!res.ok) throw new Error("No se pudo obtener la informacion del arbol.");

        const a = await res.json();
        document.getElementById('edit-id_arbol').value = a.id_arbol;
        document.getElementById('edit-codigo').value = a.codigo_etiqueta;
        document.getElementById('edit-comun').value = a.nombre_comun;
        document.getElementById('edit-cientifico').value = a.nombre_cientifico;
        document.getElementById('edit-desc').value = a.descripcion;
        document.getElementById('edit-lat').value = a.latitud;
        document.getElementById('edit-lng').value = a.longitud;

        $('#modalEditarArbol').modal('show');
    } catch(e) { 
        console.error("Error cargando arbol:", e); 
        alert("Hubo un error al intentar editar el registro.");
    }
};

window.eliminarArbol = async function(id) {
    if(!confirm("Advertencia: Se eliminara el arbol y todo su historial medico. Continuar?")) return;
    try {
        const res = await fetch(`/api/arboles/${id}`, { method: 'DELETE' });
        if((await res.json()).success) {
            cargarTablaInventario();
        } else {
            alert("No se pudo eliminar el registro.");
        }
    } catch(e) { 
        console.error("Error al eliminar:", e); 
    }
};

// ==========================================
// MAPA Y DETECCION TURF.JS
// ==========================================
$('#modalNuevoArbol').on('shown.bs.modal', async function () {
    if (!mapRegistro) {
        mapRegistro = L.map('mapaSeleccion').setView([19.7267, -101.1619], 16);
        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png').addTo(mapRegistro);

        try {
            const res = await fetch('/api/sitios');
            const zonas = await res.json();
            zonas.forEach(z => {
                if (z.coordenadas_poligono) {
                    const geojson = JSON.parse(z.coordenadas_poligono);
                    const capa = L.geoJSON(geojson, { style: { color: '#009688', weight: 2, fillOpacity: 0.15 } }).addTo(mapRegistro);
                    poligonosZonas.push({ id: z.id_sitio, nombre: z.nombre_zona, layer: capa });
                }
            });
        } catch (error) { console.error("Error cargando zonas para el mapa", error); }

        mapRegistro.on('click', function(e) {
            const lat = e.latlng.lat, lng = e.latlng.lng;
            if (markerRegistro) mapRegistro.removeLayer(markerRegistro);
            markerRegistro = L.marker([lat, lng]).addTo(mapRegistro);

            document.getElementById('lat').value = lat.toFixed(6);
            document.getElementById('lng').value = lng.toFixed(6);

            const punto = turf.point([lng, lat]);
            let zonaDetectada = false;

            for (let zona of poligonosZonas) {
                let polyGeo = zona.layer.toGeoJSON();
                let inside = false;
                if (polyGeo.type === 'FeatureCollection') {
                    for (let f of polyGeo.features) { if (turf.booleanPointInPolygon(punto, f)) inside = true; }
                } else { if (turf.booleanPointInPolygon(punto, polyGeo)) inside = true; }

                if (inside) {
                    document.getElementById('id_sitio').value = zona.id;
                    document.getElementById('zona-detectada-text').innerHTML = `${zona.nombre}`;
                    zonaDetectada = true; 
                    break;
                }
            }
            if(!zonaDetectada) {
                document.getElementById('id_sitio').value = "";
                document.getElementById('zona-detectada-text').innerHTML = `Fuera de zona UTM`;
            }
        });
    } else { 
        mapRegistro.invalidateSize(); 
    }
});

// ==========================================
// BOTON INATURALIST
// ==========================================
document.getElementById('btn-autocompletar').addEventListener('click', async () => {
    const nombreBusqueda = document.querySelector('input[name="nombre_comun"]').value;
    const inputCientifico = document.querySelector('input[name="nombre_cientifico"]');
    const inputDesc = document.querySelector('textarea[name="descripcion"]');

    if (!nombreBusqueda) return alert("Escribe un nombre comun primero");

    const btn = document.getElementById('btn-autocompletar');
    btn.innerHTML = '...'; btn.disabled = true;

    try {
        const res = await fetch(`https://api.inaturalist.org/v1/taxa?q=${encodeURIComponent(nombreBusqueda)}&locale=es&per_page=1`);
        const data = await res.json();
        if (data.results && data.results.length > 0) {
            const taxa = data.results[0];
            inputCientifico.value = taxa.name;
            if (taxa.wikipedia_summary) {
                let resumen = taxa.wikipedia_summary.replace(/<[^>]*>?/gm, '');
                inputDesc.value = resumen.split('\n')[0];
            } else {
                inputDesc.value = `Especie perteneciente al genero ${taxa.name}.`;
            }
        } else {
            alert("No se encontraron resultados botánicos.");
        }
    } catch (e) {
        console.error("Error consultando iNaturalist", e);
    } finally {
        btn.innerHTML = ''; btn.disabled = false;
    }
});



// UBICACION: public/js/mapa-logic.js
document.addEventListener('DOMContentLoaded', async () => {
    const mapContainer = document.getElementById('map');
    if (!mapContainer) return; // Evita errores si no existe el div

    // 1. Carga de Sidebar
    const sidebarContainer = document.getElementById('sidebar-container');
    const cachedSidebar = sessionStorage.getItem('sidebarHTML');
    if (cachedSidebar) {
        sidebarContainer.innerHTML = cachedSidebar;
    } else {
        const r = await fetch('components/sidebar.html');
        const html = await r.text();
        sessionStorage.setItem('sidebarHTML', html);
        sidebarContainer.innerHTML = html;
    }
    document.body.classList.add('listo');

    // 2. Inicializar Mapa
    const map = L.map('map').setView([19.7267, -101.1619], 17);
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png').addTo(map);

    const icon = L.divIcon({
        html: '',
        className: 'custom-tree', iconSize: [10, 10], iconAnchor: [12, 18]
    });

    // 3. Cargar Datos
    try {
        const resZonas = await fetch('/api/sitios');
        const zonas = await resZonas.json();
        zonas.forEach(z => {
            if (z.coordenadas_poligono) {
                const layer = L.geoJSON(JSON.parse(z.coordenadas_poligono), { 
                    style: { color: '#008B8B', weight: 2, fillOpacity: 0.15 } 
                }).addTo(map);
                layer.on('click', () => mostrarInfoZona(z));
            }
        });

        const resArboles = await fetch('/api/dashboard-stats');
        const data = await resArboles.json();
        data.arboles.forEach(a => {
            const m = L.marker([a.latitud, a.longitud], { icon }).addTo(map);
            m.on('click', (e) => { 
                L.DomEvent.stopPropagation(e); 
                mostrarInfoArbol(a); 
            });
        });
    } catch (e) { console.error("Error cargando datos del mapa:", e); }
});

