    document.getElementById('info-panel').innerHTML = `




${a.nombre_comun}
            ${a.estado || 'N/A'}


                Etiqueta: ${a.codigo_etiqueta}

                Zona: ${a.nombre_zona || 'General'}

            Ver Expediente
        `;
}

