const express = require('express');
const path = require('path');
const cors = require('cors');
const multer = require('multer');
const fs = require('fs');
const db = require('./src/config/db');
const bcrypt = require('bcryptjs');

const app = express();
const PORT = 3000;

app.use(cors());
app.use(express.json());
app.use(express.static(path.join(__dirname, 'public')));

// carpeta uploads
const uploadDir = path.join(__dirname, 'public', 'uploads');
if (!fs.existsSync(uploadDir)) fs.mkdirSync(uploadDir, { recursive: true });

// multer config
const storage = multer.diskStorage({
    destination: (req, file, cb) => cb(null, uploadDir),
    filename: (req, file, cb) => {
        const unique = Date.now() + '-' + Math.round(Math.random() * 1E9);
        cb(null, 'evidencia_' + unique + path.extname(file.originalname));
    }
});
const upload = multer({ storage });

// ---------------- AUTH ----------------
app.post('/api/login', async (req, res) => {
    try {
        const { matricula, password } = req.body;
        const [rows] = await db.query('SELECT * FROM usuario WHERE matricula = ?', [matricula]);

        if (rows.length === 0) return res.status(401).json({ success: false });

        const user = rows[0];
        const match = await bcrypt.compare(password, user.password);

        if (!match) return res.status(401).json({ success: false });

        delete user.password;
        user.rol_nombre = user.id_rol === 1 ? 'Administrador' : 'Voluntario Activo';

        res.json({ success: true, user });
    } catch (e) {
        console.error(e);
        res.status(500).json({ error: 'Error servidor' });
    }
});

// ---------------- DASHBOARD ----------------
app.get('/api/dashboard-stats', async (req, res) => {
    try {
        const [total] = await db.query('SELECT COUNT(*) as t FROM arbol');
        const [esp] = await db.query('SELECT COUNT(*) as t FROM especie');

        const [mapa] = await db.query(`
            SELECT a.*, e.nombre_comun, s.nombre_zona,
            (SELECT estado_salud FROM seguimiento 
             WHERE id_arbol = a.id_arbol 
             ORDER BY fecha_revision DESC LIMIT 1) as estado
            FROM arbol a
            JOIN especie e ON a.id_especie = e.id_especie
            LEFT JOIN sitio s ON a.id_sitio = s.id_sitio
        `);

        res.json({
            totalArboles: total[0].t,
            totalEspecies: esp[0].t,
            arboles: mapa
        });
    } catch (e) {
        console.error(e);
        res.status(500).json({ error: 'Error servidor' });
    }
});

// ---------------- EXPEDIENTE ----------------
app.get('/api/arbol/expediente/:codigo', async (req, res) => {
    try {
        const { codigo } = req.params;

        const [arbol] = await db.query(`
            SELECT a.*, e.nombre_comun, e.nombre_cientifico, s.nombre_zona
            FROM arbol a
            JOIN especie e ON a.id_especie = e.id_especie
            LEFT JOIN sitio s ON a.id_sitio = s.id_sitio
            WHERE a.codigo_etiqueta = ?
        `, [codigo]);

        if (arbol.length === 0) {
            return res.status(404).json({ error: 'No encontrado' });
        }

        const [historial] = await db.query(`
            SELECT s.*, u.nombre as usuario_nombre
            FROM seguimiento s
            LEFT JOIN usuario u ON s.id_usuario = u.id_usuario
            WHERE s.id_arbol = ?
            ORDER BY fecha_revision DESC
        `, [arbol[0].id_arbol]);

        res.json({ arbol: arbol[0], historial });

    } catch (e) {
        console.error(e);
        res.status(500).json({ error: 'Error servidor' });
    }
});

// ---------------- SEGUIMIENTO ----------------

// crear
app.post('/api/seguimiento', upload.single('foto'), async (req, res) => {
    try {
        const { id_arbol, estado_salud, comentarios, id_usuario } = req.body;

        await db.query(`
            INSERT INTO seguimiento 
            (fecha_revision, estado_salud, comentarios, foto_url, id_arbol, id_usuario)
            VALUES (NOW(), ?, ?, ?, ?, ?)
        `, [
            estado_salud,
            comentarios,
            req.file ? req.file.filename : null,
            id_arbol,
            id_usuario || 1
        ]);

        res.json({ success: true });

    } catch (e) {
        console.error(e);
        res.status(500).json({ error: 'Error servidor' });
    }
});

// editar
app.put('/api/seguimiento/:id', async (req, res) => {
    try {
        const { estado_salud, comentarios } = req.body;

        await db.query(`
            UPDATE seguimiento
            SET estado_salud = ?, comentarios = ?
            WHERE id_seguimiento = ?
        `, [estado_salud, comentarios, req.params.id]);

        res.json({ success: true });

    } catch (e) {
        console.error(e);
        res.status(500).json({ error: 'Error servidor' });
    }
});

// eliminar
app.delete('/api/seguimiento/:id', async (req, res) => {
    try {
        await db.query('DELETE FROM seguimiento WHERE id_seguimiento = ?', [req.params.id]);
        res.json({ success: true });
    } catch (e) {
        console.error(e);
        res.status(500).json({ error: 'Error servidor' });
    }
});

// ---------------- ADOPTAR ----------------
app.post('/api/arbol/adoptar', async (req, res) => {
    try {
        const { codigo_etiqueta, id_usuario } = req.body;

        await db.query(`
            UPDATE arbol 
            SET id_usuario = ?, fecha_asignacion = NOW()
            WHERE codigo_etiqueta = ?
        `, [id_usuario, codigo_etiqueta]);

        res.json({ success: true });

    } catch (e) {
        console.error(e);
        res.status(500).json({ error: 'Error servidor' });
    }
});

// ---------------- ARBOLES ----------------
app.post('/api/arboles', upload.single('foto'), async (req, res) => {
    const conn = await db.getConnection();
    try {
        await conn.beginTransaction();

        const { codigo_etiqueta, latitud, longitud, nombre_comun, nombre_cientifico, descripcion } = req.body;

        const [esp] = await conn.query('SELECT id_especie FROM especie WHERE nombre_comun = ?', [nombre_comun]);

        const id_esp = esp.length > 0
            ? esp[0].id_especie
            : (await conn.query(
                'INSERT INTO especie (nombre_comun, nombre_cientifico, descripcion) VALUES (?,?,?)',
                [nombre_comun, nombre_cientifico, descripcion]
            ))[0].insertId;

        await conn.query(`
            INSERT INTO arbol (codigo_etiqueta, latitud, longitud, fecha_plantado, id_especie)
            VALUES (?,?,?,CURDATE(),?)
        `, [codigo_etiqueta, latitud, longitud, id_esp]);

        await conn.commit();
        res.json({ success: true });

    } catch (e) {
        await conn.rollback();
        console.error(e);
        res.status(500).json({ error: 'Error servidor' });
    } finally {
        conn.release();
    }
});

// ---------------- REFORESTACION ----------------
app.get('/api/reforestacion', async (req, res) => {
    try {
        const [rows] = await db.query(`
            SELECT p.id_propuesta, p.nombre_propuesta,
            r.id_reforestacion, r.estado
            FROM propuesta_reforestacion p
            LEFT JOIN reforestacion r ON p.id_propuesta = r.id_propuesta
        `);

        res.json(rows);
    } catch (e) {
        console.error(e);
        res.status(500).json({ error: 'Error servidor' });
    }
});

// ---------------- SERVER ----------------
app.listen(PORT, () => {
    console.log(`Servidor en http://localhost:${PORT}`);
});
